-- 20260703120107_seed_stories.sql
-- Historias (inmersión) multi-idioma. ADITIVA (no toca las historias en).
-- stories es course-scoped (get_stories/get_story/submit_story por jz_active_course)
-- → cada curso ve las suyas. questions calificadas server-side (submit_story→jz_grade,
-- correct_answer oculto 42501). ids uuid5. audio_url → audio/stories/<id>_<i>.mp3.
begin;
insert into stories (id, course_id, cefr_level, order_index, title, subtitle, emoji, intro, est_seconds, segments, glossary, questions) values
('9b619758-3648-5db2-b0bc-fb9c5fc02476'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,'A1',1,$p$Le café de Léa$p$,$p$Léa va a un café en París por la mañana y saluda al camarero.$p$,$p$☕$p$,$p$Es una mañana de sábado en París. Léa entra en su café favorito para desayunar. Lee y escucha su pequeña historia.$p$,56,$j$[{"en": "Bonjour ! Je m'appelle Léa.", "es": "¡Buenos días! Me llamo Léa.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/9b619758-3648-5db2-b0bc-fb9c5fc02476-0.mp3"}, {"en": "J'habite à Paris avec ma famille.", "es": "Vivo en París con mi familia.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/9b619758-3648-5db2-b0bc-fb9c5fc02476-1.mp3"}, {"en": "Le matin, je vais au café près de chez moi.", "es": "Por la mañana, voy al café cerca de mi casa.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/9b619758-3648-5db2-b0bc-fb9c5fc02476-2.mp3"}, {"en": "Le serveur me dit : « Bonjour, ça va ? »", "es": "El camarero me dice: «Buenos días, ¿cómo estás?»", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/9b619758-3648-5db2-b0bc-fb9c5fc02476-3.mp3"}, {"en": "Je commande un café et un croissant.", "es": "Pido un café y un cruasán.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/9b619758-3648-5db2-b0bc-fb9c5fc02476-4.mp3"}, {"en": "Le croissant est très bon et le café est chaud.", "es": "El cruasán está muy bueno y el café está caliente.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/9b619758-3648-5db2-b0bc-fb9c5fc02476-5.mp3"}, {"en": "Merci, monsieur ! À demain !", "es": "¡Gracias, señor! ¡Hasta mañana!", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/9b619758-3648-5db2-b0bc-fb9c5fc02476-6.mp3"}]$j$::jsonb,$j$[{"word": "bonjour", "translation": "buenos días / hola"}, {"word": "le café", "translation": "el café (bebida y local)"}, {"word": "le matin", "translation": "la mañana"}, {"word": "le serveur", "translation": "el camarero"}, {"word": "un croissant", "translation": "un cruasán"}, {"word": "chaud", "translation": "caliente"}]$j$::jsonb,$j$[{"type": "multiple_choice", "skill": "reading", "prompt": "¿Cómo se llama la protagonista?", "payload": {"options": ["Léa", "Marie", "Sophie"]}, "difficulty": 0.2, "correct_answer": {"value": "Léa"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿En qué ciudad vive?", "payload": {"options": ["Lyon", "Paris", "Nice"]}, "difficulty": 0.2, "correct_answer": {"value": "Paris"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿A qué hora del día va al café?", "payload": {"options": ["le matin", "le soir", "la nuit"]}, "difficulty": 0.2, "correct_answer": {"value": "le matin"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿Qué pide en el café?", "payload": {"options": ["un café y un croissant", "un té y pan", "un jugo y una tarta"]}, "difficulty": 0.2, "correct_answer": {"value": "un café y un croissant"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿Cómo está el café que le sirven?", "payload": {"options": ["chaud", "froid", "mauvais"]}, "difficulty": 0.2, "correct_answer": {"value": "chaud"}}]$j$::jsonb),
('55578721-71b2-57e1-8d2c-ecd5f96fa05b'::uuid,'20000000-0000-0000-0000-000000000004'::uuid,'A1',1,$p$Un caffè al bar$p$,$p$Marco entra en un bar de Roma por la mañana y pide un café antes del trabajo.$p$,$p$☕$p$,$p$Es de mañana en Roma y Marco tiene sueño. Entra en su bar de siempre para tomar un café; lee y escucha su breve rutina.$p$,56,$j$[{"en": "È mattina a Roma.", "es": "Es de mañana en Roma.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55578721-71b2-57e1-8d2c-ecd5f96fa05b-0.mp3"}, {"en": "Marco entra nel bar.", "es": "Marco entra en el bar.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55578721-71b2-57e1-8d2c-ecd5f96fa05b-1.mp3"}, {"en": "\"Buongiorno!\" dice il barista.", "es": "\"¡Buenos días!\" dice el barista.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55578721-71b2-57e1-8d2c-ecd5f96fa05b-2.mp3"}, {"en": "\"Buongiorno! Un caffè, per favore.\"", "es": "\"¡Buenos días! Un café, por favor.\"", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55578721-71b2-57e1-8d2c-ecd5f96fa05b-3.mp3"}, {"en": "Marco beve il caffè al banco.", "es": "Marco bebe el café en la barra.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55578721-71b2-57e1-8d2c-ecd5f96fa05b-4.mp3"}, {"en": "Il caffè è caldo e buono.", "es": "El café está caliente y bueno.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55578721-71b2-57e1-8d2c-ecd5f96fa05b-5.mp3"}, {"en": "\"Grazie, arrivederci!\" e Marco va al lavoro.", "es": "\"¡Gracias, hasta luego!\" y Marco se va al trabajo.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55578721-71b2-57e1-8d2c-ecd5f96fa05b-6.mp3"}]$j$::jsonb,$j$[{"word": "buongiorno", "translation": "buenos días"}, {"word": "il bar", "translation": "el bar / la cafetería"}, {"word": "un caffè", "translation": "un café"}, {"word": "per favore", "translation": "por favor"}, {"word": "il banco", "translation": "la barra (del bar)"}, {"word": "il lavoro", "translation": "el trabajo"}]$j$::jsonb,$j$[{"type": "multiple_choice", "skill": "reading", "prompt": "¿En qué ciudad está Marco?", "payload": {"options": ["Roma", "Milano", "Napoli"]}, "difficulty": 0.2, "correct_answer": {"value": "Roma"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿A qué lugar entra Marco?", "payload": {"options": ["en el bar", "en la escuela", "en la casa"]}, "difficulty": 0.2, "correct_answer": {"value": "en el bar"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿Qué pide Marco?", "payload": {"options": ["un caffè", "un tè", "un'acqua"]}, "difficulty": 0.2, "correct_answer": {"value": "un caffè"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿Cómo está el café según la historia?", "payload": {"options": ["caldo e buono", "freddo", "cattivo"]}, "difficulty": 0.2, "correct_answer": {"value": "caldo e buono"}}, {"type": "multiple_choice", "skill": "reading", "prompt": "¿A dónde va Marco al final?", "payload": {"options": ["al lavoro", "a casa", "al parco"]}, "difficulty": 0.2, "correct_answer": {"value": "al lavoro"}}]$j$::jsonb)
on conflict (id) do update set title=excluded.title, subtitle=excluded.subtitle, emoji=excluded.emoji, intro=excluded.intro, est_seconds=excluded.est_seconds, segments=excluded.segments, glossary=excluded.glossary, questions=excluded.questions;
commit;